window.renderQuranQuizzesDashboard = function() {
    const container = document.getElementById('quranQuizzesContainer');
    if (!container) return;

    let categoriesHtml = "";
    const categories = Object.keys(window.quranAcademyQuizzes);

    const icons = {
        "حفظ القرآن وتدبر الآيات": "📖",
        "تفسير القرآن الكريم": "📝",
        "معاني كلمات القرآن": "📿",
        "أسباب نزول الآيات والسياق": "📜"
    };

    const descriptions = {
        "حفظ القرآن وتدبر الآيات": "فحص المتانة، المتشابهات اللفظية، وروابط الآيات والأجزاء بدقة.",
        "تفسير القرآن الكريم": "معاني السور، أراء ابن كثير والسلف، ومقاصد التشريع الحكيمة.",
        "معاني كلمات القرآن": "كشط وتفسير الكلمات الغريبة والعميقة بالسند المأثور اللغوي.",
        "أسباب نزول الآيات والسياق": "القصص التاريخية، الحوادث، والأشخاص الذين نزلت فيهم آيات الأحكام الحية."
    };

    categories.forEach(cat => {
        categoriesHtml += `
        <div class="comm-card" style="background: var(--card); border: 1px solid var(--border); border-right: 4px solid var(--gold); padding: 16px; margin-bottom: 15px; direction: rtl; text-align: right;">
            <div style="display: flex; align-items: center; gap: 10px; margin-bottom: 8px;">
                <span style="font-size: 26px;">${icons[cat] || '✨'}</span>
                <strong style="color: var(--gold); font-size: 16px; font-family: 'Amiri', serif;">${cat}</strong>
            </div>
            <p style="color: var(--text2); font-size: 12px; margin-bottom: 15px; line-height: 1.5;">${descriptions[cat] || ''}</p>
            
            <div style="font-size: 11px; color: var(--text); margin-bottom: 8px; font-weight: bold;">اختر المستوى للبدء في الاختبار الشامل (30 سؤالاً):</div>
            <div style="display: flex; gap: 8px;">
                <button onclick="window.startAcademyQuizEngine('${cat}', 'سهل')" style="flex: 1; background: rgba(76,175,80,0.12); color: #6fbf73; border: 1px solid rgba(76,175,80,0.3); padding: 8px; border-radius: 8px; font-weight: bold; font-family: 'Amiri', serif; font-size: 12px; cursor: pointer; transition: 0.2s;">🌿 سهل (30 سؤالاً)</button>
                <button onclick="window.startAcademyQuizEngine('${cat}', 'متوسط')" style="flex: 1; background: rgba(212,175,55,0.12); color: var(--gold); border: 1px solid rgba(212,175,55,0.3); padding: 8px; border-radius: 8px; font-weight: bold; font-family: 'Amiri', serif; font-size: 12px; cursor: pointer; transition: 0.2s;">⚡ متوسط (30 سؤالاً)</button>
                <button onclick="window.startAcademyQuizEngine('${cat}', 'صعب')" style="flex: 1; background: rgba(255,77,77,0.12); color: #ff4d4d; border: 1px solid rgba(255,77,77,0.3); padding: 8px; border-radius: 8px; font-weight: bold; font-family: 'Amiri', serif; font-size: 12px; cursor: pointer; transition: 0.2s;">🔥 صعب (30 سؤالاً)</button>
            </div>
        </div>`;
    });

    container.innerHTML = categoriesHtml;
};

window.startAcademyQuizEngine = function(category, level) {
    const container = document.getElementById('quranQuizzesContainer');
    if (!container) return;

    const selectedQuestions = window.quranAcademyQuizzes[category][level];

    window.currentActiveQuranQuiz = {
        category: category,
        level: level,
        questions: selectedQuestions,
        answers: new Array(selectedQuestions.length).fill(null)
    };

    window.renderAcademyQuizQuestionsHTML();
};

window.renderAcademyQuizQuestionsHTML = function() {
    const container = document.getElementById('quranQuizzesContainer');
    const qData = window.currentActiveQuranQuiz;
    if (!container || !qData) return;

    let html = `
    <div class="comm-card" style="border-right: 4px solid var(--gold); direction: rtl; text-align: right; margin-bottom: 15px; background: var(--bg2); padding: 14px; border-radius: 12px;">
        <strong style="color: var(--gold); font-family: 'Amiri', serif; font-size: 16px;">📍 القسم: ${qData.category} (الاختبار الموحد الشامل)</strong>
        <span style="display: block; font-size: 12px; color: var(--text2); margin-top: 2px;">المستوى الحالي: <span style="font-weight: bold; color: #ff4d4d;">${qData.level}</span> (إجمالي ${qData.questions.length} سؤالاً - شرط النجاح 29 أو 30)</span>
    </div>`;

    qData.questions.forEach((qItem, qIdx) => {
        html += `
        <div class="comm-card" style="margin-bottom: 14px; background: var(--card); border: 1px solid var(--border); padding: 14px; border-radius: 12px; direction: rtl; text-align: right;">
            <strong style="color: var(--text); font-size: 14px; display: block; margin-bottom: 10px; line-height: 1.5;">س ${qIdx + 1}: ${qItem.q}</strong>
            <div style="display: flex; flex-direction: column; gap: 8px;">
                ${qItem.os.map((option, oIdx) => {
                    const isSelected = qData.answers[qIdx] === oIdx;
                    return `
                    <label style="display: flex; align-items: center; gap: 8px; background: ${isSelected ? 'rgba(212,175,55,0.1)' : 'transparent'}; border: 1px solid ${isSelected ? 'var(--gold)' : 'var(--border)'}; padding: 10px 14px; border-radius: 8px; cursor: pointer; font-size: 13px; color: ${isSelected ? 'var(--gold)' : 'var(--text)'}; transition: 0.15s;">
                        <input type="radio" name="acad_q_${qIdx}" value="${oIdx}" ${isSelected ? 'checked' : ''} onchange="window.selectAcademyQuizAnswer(${qIdx}, ${oIdx})" style="accent-color: var(--gold);" />
                        ${option}
                    </label>`;
                }).join('')}
            </div>
        </div>`;
    });

    html += `
    <div style="display: flex; gap: 10px; margin-top: 20px; direction: rtl;">
        <button onclick="window.submitAcademyQuizResult()" style="flex: 1; background: var(--gold); color: #111; border: none; padding: 14px; border-radius: 12px; font-weight: bold; font-family: 'Amiri', serif; font-size: 15px; cursor: pointer; box-shadow: 0 4px 15px rgba(212,175,55,0.25);">📥 تصحيح المسابقة ومعاينة النتيجة الحية</button>
        <button onclick="window.renderQuranQuizzesDashboard()" style="background: transparent; border: 1px solid var(--border); color: var(--text2); padding: 14px 20px; border-radius: 12px; font-family: 'Amiri', serif; font-size: 14px; cursor: pointer;">انسحاب ورجوع ‹</button>
    </div>`;

    container.innerHTML = html;
    window.scrollTo({ top: 0, behavior: 'smooth' });
};

window.selectAcademyQuizAnswer = function(qIdx, oIdx) {
    if (window.currentActiveQuranQuiz) {
        window.currentActiveQuranQuiz.answers[qIdx] = oIdx;
    }
};
window.submitAcademyQuizResult = function() {
    const qData = window.currentActiveQuranQuiz;
    const container = document.getElementById('quranQuizzesContainer');
    if (!qData || !container) return;

    const unanswered = qData.answers.filter(a => a === null).length;
    if (unanswered > 0) {
        alert(`⚠️ عذراً يا صاحب الأثر، لسه باقيلك ${unanswered} سؤال ما حلتهمش!`);
        return;
    }

    let score = 0;
    let wrongQuestions = []; // مصفوفة لتخزين الأسئلة الخاطئة
    
    qData.questions.forEach((qItem, idx) => {
        if (qData.answers[idx] === qItem.a) {
            score++;
        } else {
            // إضافة السؤال الذي تم الخطأ فيه إلى التقرير
            wrongQuestions.push({
                question: qItem.q,
                correctAnswer: qItem.os[qItem.a],
                userAnswer: qItem.os[qData.answers[idx]]
            });
        }
    });

    const passed = score >= 29;
    const finalUserName = localStorage.getItem('athr_user_name') || "طالب الأثر الطيب";

    let resultHtml = `
    <div class="comm-card" style="text-align: center; padding: 20px; background: var(--bg2); border: 1px solid var(--border); direction: rtl; border-radius: 12px;">
        <h3 style="color: ${passed ? '#4caf50' : '#ff4d4d'}; font-family: 'Amiri', serif;">${passed ? 'مَاشَاءَ اللَّه! حُزْتَ مَرْتَبَةَ الإِتْقَانِ' : 'مُحَاوَلَةٌ طَيِّبَةٌ'}</h3>
        <p style="font-size: 20px;">الدرجة: <strong>${score} / 30</strong></p>
    `;

    // إذا كان هناك أخطاء، نعرضها في قائمة
    if (wrongQuestions.length > 0) {
        resultHtml += `<div style="text-align: right; margin: 20px 0; background: #fff; padding: 15px; border-radius: 10px;">
            <h4 style="color: #d32f2f;">📝 تقرير الأخطاء (الأسئلة التي تحتاج مراجعة):</h4>
            ${wrongQuestions.map((err, i) => `
                <div style="margin-bottom: 15px; border-bottom: 1px solid #eee; padding-bottom: 5px;">
                    <p style="font-weight: bold; margin:0;">${i+1}. ${err.question}</p>
                    <p style="color: #4caf50; margin:0;">✅ الإجابة الصحيحة: ${err.correctAnswer}</p>
                    <p style="color: #ff4d4d; margin:0;">❌ إجابتك: ${err.userAnswer}</p>
                </div>
            `).join('')}
        </div>`;
    }

    if (passed) {
        resultHtml += `
        <button onclick="window.showAcademySpecialCertificateModal('${finalUserName}', '${qData.category}', '${qData.level}', '${score}')" style="background: #4caf50; color: #fff; border: none; padding: 12px; width: 100%; border-radius: 8px; cursor: pointer;">🎓 عَرْضُ وَتَحْمِيلُ الشَّهَادَةِ</button>`;
    }

    resultHtml += `<br><br><button onclick="window.renderQuranQuizzesDashboard()" style="background: var(--card); border: 1px solid var(--border); padding: 10px; width: 100%; cursor: pointer;">العودة للرئيسية</button></div>`;

    container.innerHTML = resultHtml;
    window.scrollTo({ top: 0, behavior: 'smooth' });
};

